import { mkdir } from "node:fs/promises";
import path from "node:path";
import { expect, test, type Page } from "playwright/test";

// Generated by Intent POC. The source-scoped screenshot subtree is overwritten in place when this tracked spec is regenerated.
const baseUrl = process.env.INTENT_POC_BASE_URL ?? "http://127.0.0.1:6006";
const screenshotRoot = process.env.INTENT_POC_E2E_SCREENSHOT_ROOT ?? "/home/andre/Desktop/GeniusMonkey/Intent POC/artifacts/library/intent-poc-app";

const requiredUiStates = [
  {
    "stateId": "theme-mode",
    "label": "Theme mode",
    "description": "The demo app supports light and dark theme states that materially change contrast, tokens, and screenshot evidence.",
    "requestedValue": "light",
    "activation": [
      {
        "type": "query-param",
        "target": "dark",
        "values": {
          "light": "false",
          "dark": "true"
        },
        "notes": [
          "The demo app now honors the dark query parameter across Studio and library routes for deterministic verification."
        ]
      },
      {
        "type": "ui-control",
        "target": "[data-testid='theme-toggle']",
        "values": {
          "light": "false",
          "dark": "true"
        },
        "notes": [
          "The library surface toggle remains available for manual verification flows."
        ]
      },
      {
        "type": "ui-control",
        "target": "#dark-mode-toggle",
        "values": {
          "light": "false",
          "dark": "true"
        },
        "notes": [
          "Intent Studio keeps an explicit toggle for interactive review during manual sessions."
        ]
      }
    ],
    "verificationStrategies": [
      "ui-interaction-playwright"
    ],
    "notes": [
      "Stateful UI bugs should declare and verify the requested UI state before screenshot evidence is trusted.",
      "Prefer reusable state activation contracts over prompt-specific routing or one-off checkpoint logic.",
      "Theme-sensitive UI bugs require paired light-mode and dark-mode screenshot evidence; do not accept a dark-mode-only capture set.",
      "Verify the active theme state before trusting screenshot comparisons.",
      "Prefer the shared dark query parameter during generated verification so screenshots start in the requested theme.",
      "Dark-theme verification should keep a light-mode reference screenshot alongside the dark-mode target evidence."
    ],
    "reason": "Prompt requests the Theme mode UI state with value \"light\"."
  }
] as const;

function buildUrlWithUiStates(routePath: string, requirements: typeof requiredUiStates): string {
  const url = new URL(routePath, baseUrl);
  for (const requirement of requirements) {
    if (!requirement.requestedValue) {
      continue;
    }

    for (const activation of requirement.activation) {
      if (activation.type !== "query-param" || !activation.target) {
        continue;
      }

      const activationValue = activation.values[requirement.requestedValue];
      if (typeof activationValue === "string" && activationValue.length > 0) {
        url.searchParams.set(activation.target, activationValue);
      }
    }
  }

  return url.toString();
}

function isUiStateRouteSatisfied(page: Page, requirement: (typeof requiredUiStates)[number]): boolean {
  const currentUrl = new URL(page.url());
  for (const activation of requirement.activation) {
    if (activation.type !== "query-param" || !activation.target) {
      continue;
    }

    const activationValue = activation.values[requirement.requestedValue];
    if (typeof activationValue !== "string" || activationValue.length === 0) {
      continue;
    }

    if (currentUrl.searchParams.get(activation.target) === activationValue) {
      return true;
    }
  }

  return false;
}

async function applyUiStateRequirements(page: Page, requirements: typeof requiredUiStates): Promise<void> {
  for (const requirement of requirements) {
    if (!requirement.requestedValue) {
      continue;
    }

    if (isUiStateRouteSatisfied(page, requirement)) {
      continue;
    }

    for (const activation of requirement.activation) {
      if (activation.type !== "ui-control" || !activation.target) {
        continue;
      }

      const activationValue = activation.values[requirement.requestedValue];
      if (!activationValue || !/^(true|1|on|enabled|active)$/i.test(activationValue)) {
        continue;
      }

      const control = page.locator(activation.target).first();
      if ((await control.count()) === 0) {
        continue;
      }

      await expect(control, `${requirement.label ?? requirement.stateId} control should be visible before activation.`).toBeVisible();
      const urlBeforeActivation = page.url();
      await control.click();
      if (page.url() !== urlBeforeActivation) {
        await page.waitForLoadState("load");
      }
      break;
    }
  }
}

test.describe("Intent Studio Run Indicator", () => {
  test("Display active test status in Intent Studio", async ({ page }) => {
    test.setTimeout(121000);
    await test.step("Navigate to Intent Studio", async () => {
      await page.goto(buildUrlWithUiStates("/?dark=false", requiredUiStates), { waitUntil: "domcontentloaded" });
      await applyUiStateRequirements(page, requiredUiStates);
      await expect(page.locator("body"), "Studio is loaded and prompt input is ready.").toBeVisible();
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "navigate-to-intent-studio.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Fill prompt", async () => {
      const target = page.locator("#prompt-input");
      await expect(target, "Prompt input is populated to enable submit.").toBeVisible();
      await target.fill("Run a test suite");
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "fill-prompt.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Workflow Readiness Ready", async () => {
      await page.waitForSelector("#workflow-readiness-status", { timeout: 30000 });
      const target = page.locator("#workflow-readiness-status").first();
      await expect(target, "The Studio workflow readiness resolves before the run button is used.").toBeVisible({ timeout: 30000 });
      await expect(target, "The Studio workflow readiness resolves before the run button is used.").toHaveAttribute("class", new RegExp("target-ready"), { timeout: 30000 });
      const attributeValue = await target.getAttribute("class");
      expect(attributeValue, "The Studio workflow readiness resolves before the run button is used.").toBeTruthy();
      expect(attributeValue ?? "", "The Studio workflow readiness resolves before the run button is used.").toContain("target-ready");
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "workflow-readiness-ready.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("First click to generate draft", async () => {
      const target = page.locator("[data-testid='run-tests-button']");
      await expect(target, "Submit button clicked to initiate scoping.").toBeVisible();
      await expect(target, "Submit button clicked to initiate scoping.").toBeEnabled();
      await target.click();
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "first-click-to-generate-draft.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Scoping Draft Ready", async () => {
      const target = page.locator("text=Scoping IDD draft ready.");
      await expect(target, "The scoping draft is ready for approval before execution starts.").toBeVisible({ timeout: 30000 });
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "scoping-draft-ready.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Second click to execute", async () => {
      const target = page.locator("[data-testid='run-tests-button']");
      await expect(target, "Submit button clicked to approve draft and start execution.").toBeVisible();
      await expect(target, "Submit button clicked to approve draft and start execution.").toBeEnabled();
      await target.click();
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "second-click-to-execute.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Verify running state", async () => {
      const target = page.locator("[data-testid='test-status-indicator']");
      await expect(target, "Status indicator shows running state.").toBeVisible();
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "verify-running-state.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Verify state code", async () => {
      const target = page.locator("[data-testid='test-status-indicator']").first();
      await expect(target, "Indicator contains RUNNING state code.").toBeVisible();
      await expect(target, "Indicator contains RUNNING state code.").toHaveAttribute("data-state-code", new RegExp("RUNNING"));
      const attributeValue = await target.getAttribute("data-state-code");
      expect(attributeValue, "Indicator contains RUNNING state code.").toBeTruthy();
      expect(attributeValue ?? "", "Indicator contains RUNNING state code.").toContain("RUNNING");
      const screenshotPath = path.join(screenshotRoot, "bdd/test-status-indicator-spec", "verify-state-code.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
  });
});
